CREATE OR REPLACE FUNCTION validate_encounter_status_transition() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ BEGIN IF OLD.status = NEW.status THEN RETURN NEW; END IF; IF NOT ( (OLD.status = 'planned' AND NEW.status IN ('arrived', 'in-progress', 'cancelled')) OR (OLD.status = 'arrived' AND NEW.status IN ('triaged', 'in-progress', 'cancelled')) OR (OLD.status = 'triaged' AND NEW.status IN ('in-progress', 'cancelled')) OR (OLD.status = 'in-progress' AND NEW.status IN ('onleave', 'finished', 'cancelled')) OR (OLD.status = 'onleave' AND NEW.status IN ('in-progress', 'finished')) OR (OLD.status = 'cancelled' AND NEW.status = 'planned') ) THEN RAISE EXCEPTION 'Invalid encounter status transition: % -> %', OLD.status, NEW.status; END IF; RETURN NEW; END; $fn$;
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = 'trg_encounter_status_transition') THEN CREATE TRIGGER trg_encounter_status_transition BEFORE UPDATE OF status ON encounters FOR EACH ROW EXECUTE FUNCTION validate_encounter_status_transition(); END IF; END $$;
CREATE OR REPLACE FUNCTION validate_condition_status_transition() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ BEGIN IF OLD.status = NEW.status THEN RETURN NEW; END IF; IF NOT ( (OLD.status = 'active' AND NEW.status IN ('recurrence', 'relapse', 'resolved', 'inactive')) OR (OLD.status = 'recurrence' AND NEW.status IN ('active', 'inactive', 'resolved')) OR (OLD.status = 'relapse' AND NEW.status IN ('active', 'inactive', 'resolved')) OR (OLD.status = 'inactive' AND NEW.status IN ('active', 'recurrence', 'relapse', 'resolved')) OR (OLD.status = 'resolved' AND NEW.status IN ('active', 'recurrence', 'relapse')) ) THEN RAISE EXCEPTION 'Invalid condition status transition: % -> %', OLD.status, NEW.status; END IF; RETURN NEW; END; $fn$;
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = 'trg_condition_status_transition') THEN CREATE TRIGGER trg_condition_status_transition BEFORE UPDATE OF status ON conditions FOR EACH ROW EXECUTE FUNCTION validate_condition_status_transition(); END IF; END $$;
CREATE OR REPLACE FUNCTION validate_care_plan_status_transition() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ BEGIN IF OLD.status = NEW.status THEN RETURN NEW; END IF; IF NOT ( (OLD.status = 'draft' AND NEW.status IN ('active', 'revoked')) OR (OLD.status = 'active' AND NEW.status IN ('on-hold', 'completed', 'revoked')) OR (OLD.status = 'on-hold' AND NEW.status IN ('active', 'revoked')) OR (OLD.status = 'completed' AND NEW.status = 'active') OR (OLD.status = 'unknown' AND NEW.status IN ('draft', 'active')) ) THEN RAISE EXCEPTION 'Invalid care_plan status transition: % -> %', OLD.status, NEW.status; END IF; RETURN NEW; END; $fn$;
DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_trigger WHERE tgname = 'trg_care_plan_status_transition') THEN CREATE TRIGGER trg_care_plan_status_transition BEFORE UPDATE OF status ON care_plans FOR EACH ROW EXECUTE FUNCTION validate_care_plan_status_transition(); END IF; END $$;;
